describe('Cart integration', () => {
  it('renders empty state with heading and link to store', () => {
    render(<Cart />);

    expect(screen.getByRole('heading', { name: 'El carrito está vacío' })).toBeInTheDocument();
    expect(screen.getByRole('link', { name: 'Ver productos' })).toHaveAttribute('href', '/');
  });

  it('renders cart items when cart has products', () => {
    mockCartState = { ...mockCartState, cart: [MOCK_ITEM], totalItems: 2, totalPrice: 119.98, finalPrice: 119.98 };

    render(<Cart />);

    expect(screen.getByText('Auriculares Bluetooth')).toBeInTheDocument();
  });

  it('keyboard "/" focuses the coupon input', async () => {
    mockCartState = { ...mockCartState, cart: [MOCK_ITEM], totalItems: 2, totalPrice: 119.98, finalPrice: 119.98 };
    const user = userEvent.setup();
    render(<Cart />);

    // Press "/" from outside an input field
    await user.keyboard('/');

    // Coupon input should now be focused
    const couponInput = screen.getByPlaceholderText('CUPÓN10');
    expect(couponInput).toHaveFocus();
  });

  it('remove item dispatches REMOVE_ITEM and calls showToast', async () => {
    mockCartState = { ...mockCartState, cart: [MOCK_ITEM], totalItems: 2, totalPrice: 119.98, finalPrice: 119.98 };
    const user = userEvent.setup();
    render(<Cart />);

    const removeBtn = screen.getByRole('button', { name: 'cart.removeFromCart' });
    await user.click(removeBtn);

    expect(mockDispatch).toHaveBeenCalledWith(
      expect.objectContaining({ type: 'REMOVE_ITEM', payload: { id: 1 } }),
    );
    expect(mockShowToast).toHaveBeenCalledWith(
      expect.stringContaining('Auriculares Bluetooth'),
      'info',
    );
  });
});
